import{_ as e,a,b as d,c as r,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as l,o as i,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const T=JSON.parse('{"title":"Добавление канала Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/telegram.md","filePath":"ru-RU/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"ru-RU/upload/telegram.md"};function c(p,t,m,g,b,u){return i(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="добавление-канала-telegram" tabindex="-1">Добавление канала Telegram <a class="header-anchor" href="#добавление-канала-telegram" aria-label="Permalink to &quot;Добавление канала Telegram&quot;">​</a></h1><h2 id="что-подготовить-заранее" tabindex="-1">Что подготовить заранее <a class="header-anchor" href="#что-подготовить-заранее" aria-label="Permalink to &quot;Что подготовить заранее&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт Telegram</td><td>Для создания бота и канала, где будут храниться файлы.</td></tr><tr><td><code>@BotFather</code></td><td>Через него создается Telegram-бот.</td></tr><tr><td>Канал Telegram</td><td>Конечное место хранения файлов.</td></tr><tr><td><code>@userinfobot</code></td><td>Помогает получить <code>Chat ID</code> канала.</td></tr></tbody></table><h2 id="где-добавить-канал" tabindex="-1">Где добавить канал <a class="header-anchor" href="#где-добавить-канал" aria-label="Permalink to &quot;Где добавить канал&quot;">​</a></h2><ol><li>Откройте системные настройки.</li><li>Перейдите в настройки загрузки.</li><li>Нажмите Add Channel в правом верхнем углу.</li><li>Выберите <code>Telegram</code>.</li></ol><h2 id="поля-настроики" tabindex="-1">Поля настройки <a class="header-anchor" href="#поля-настроики" aria-label="Permalink to &quot;Поля настройки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Что означает</th><th>Обязательно</th></tr></thead><tbody><tr><td>Название канала</td><td>Понятное имя, например &quot;Telegram Primary&quot;.</td><td>Да</td></tr><tr><td>Активен</td><td>Включает или отключает этот канал.</td><td>Рекомендуется</td></tr><tr><td>Bot Token</td><td>Токен вашего Telegram-бота.</td><td>Да</td></tr><tr><td>Session ID (Chat ID)</td><td>Идентификатор Telegram-канала.</td><td>Да</td></tr><tr><td>Relay Proxy URL (необязательно)</td><td>Используйте только при нестабильном доступе к Telegram. Укажите полный URL прокси, включая <code>https://</code>.</td><td>Нет</td></tr><tr><td>Примечание</td><td>Заметки для дальнейшего обслуживания.</td><td>Нет</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="_1-создаите-telegram-бота" tabindex="-1">1. Создайте Telegram-бота <a class="header-anchor" href="#_1-создаите-telegram-бота" aria-label="Permalink to &quot;1. Создайте Telegram-бота&quot;">​</a></h3><ol><li>Откройте Telegram и найдите <code>@BotFather</code>.</li><li>Откройте чат и нажмите <code>Start</code>.</li><li>Отправьте <code>/newbot</code>.</li><li>По подсказкам введите отображаемое имя бота.</li><li>По подсказкам введите username бота. Обычно он должен заканчиваться на <code>bot</code>.</li><li>После создания бота <code>@BotFather</code> вернет токен.</li></ol><p>Именно этот токен нужно ввести в ImgBed в поле <code>Bot Token</code>.</p><p><img src="'+e+'" alt="Сохраните токен бота" loading="lazy"></p><h3 id="_2-создаите-канал" tabindex="-1">2. Создайте канал <a class="header-anchor" href="#_2-создаите-канал" aria-label="Permalink to &quot;2. Создайте канал&quot;">​</a></h3><ol><li>В Telegram нажмите New Channel.</li><li>Введите название канала.</li><li>Завершите создание канала.</li></ol><p>Можно использовать и публичные, и приватные каналы.</p><p><img src="'+a+'" alt="Создание канала" loading="lazy"></p><h3 id="_3-добавьте-бота-в-канал" tabindex="-1">3. Добавьте бота в канал <a class="header-anchor" href="#_3-добавьте-бота-в-канал" aria-label="Permalink to &quot;3. Добавьте бота в канал&quot;">​</a></h3><ol><li>Откройте только что созданный канал.</li><li>Перейдите в настройки канала.</li><li>Добавьте участника или администратора.</li><li>Найдите username созданного бота.</li><li>Добавьте бота в канал.</li></ol><p>Для наиболее надежной загрузки лучше выдать боту права администратора.</p><p><img src="'+d+'" alt="Приглашение бота в канал" loading="lazy"></p><h3 id="_4-получите-id-канала-через-user-info-get-id-idbot" tabindex="-1">4. Получите ID канала через User Info - Get ID - IDbot <a class="header-anchor" href="#_4-получите-id-канала-через-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Получите ID канала через User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>В Telegram найдите <code>@userinfobot</code>. Обычно он отображается как <code>User Info - Get ID - IDbot</code>.</li><li>Откройте чат и нажмите <code>Start</code>.</li><li>В вариантах бота выберите <code>Channel</code>.</li><li>В окне выбора сообщения выберите нужный канал и отправьте его в <code>@userinfobot</code>.</li><li>Когда <code>@userinfobot</code> вернет результат, скопируйте число в поле <code>Id: -100...</code>.</li></ol><p>Число, начинающееся с <code>-100</code>, и есть <code>Session ID (Chat ID)</code>, который нужен ImgBed.</p><p><img src="'+r+'" alt="Получение ID канала" loading="lazy"></p><h3 id="_5-заполните-канал-telegram-в-imgbed" tabindex="-1">5. Заполните канал Telegram в ImgBed <a class="header-anchor" href="#_5-заполните-канал-telegram-в-imgbed" aria-label="Permalink to &quot;5. Заполните канал Telegram в ImgBed&quot;">​</a></h3><p>Вернитесь в диалог настройки канала и заполните поля:</p><table tabindex="0"><thead><tr><th>Поле в интерфейсе</th><th>Значение</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Собственное имя канала, например <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Рекомендуется включить.</td></tr><tr><td>Bot Token</td><td>Токен бота из <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Число <code>-100...</code>, которое вернул <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (необязательно)</td><td>Только при необходимости, например <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>Необязательные заметки.</td></tr></tbody></table><p>Когда все заполнено, нажмите Save.</p><p><img src="'+o+`" alt="Редактирование конфигурации" loading="lazy"></p><h2 id="как-проверить" tabindex="-1">Как проверить <a class="header-anchor" href="#как-проверить" aria-label="Permalink to &quot;Как проверить&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проверка</th><th>Как проверить</th></tr></thead><tbody><tr><td>Карточка канала появилась</td><td>После сохранения на странице настроек загрузки должна появиться карточка Telegram-канала.</td></tr><tr><td>Канал можно включить</td><td>Переключатель Active должен оставаться включенным.</td></tr><tr><td>Конфигурация сохранена</td><td>В деталях должно быть видно, что Bot Token и Chat ID сохранены.</td></tr><tr><td>Загрузка работает</td><td>Загрузите тестовое изображение и убедитесь, что оно появилось в целевом Telegram-канале.</td></tr></tbody></table><h2 id="короткии-чек-лист" tabindex="-1">Короткий чек-лист <a class="header-anchor" href="#короткии-чек-лист" aria-label="Permalink to &quot;Короткий чек-лист&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Создать бота через @BotFather</span></span>
<span class="line"><span>-&gt; Сохранить Bot Token</span></span>
<span class="line"><span>-&gt; Создать Telegram-канал</span></span>
<span class="line"><span>-&gt; Добавить бота в канал и выдать права администратора</span></span>
<span class="line"><span>-&gt; Найти @userinfobot и выбрать Channel</span></span>
<span class="line"><span>-&gt; Переслать любое сообщение из канала в @userinfobot</span></span>
<span class="line"><span>-&gt; Скопировать возвращенный Id: -100...</span></span>
<span class="line"><span>-&gt; Ввести Bot Token и Chat ID в ImgBed</span></span>
<span class="line"><span>-&gt; Сохранить и загрузить тестовое изображение</span></span></code></pre></div><h2 id="ссылки" tabindex="-1">Ссылки <a class="header-anchor" href="#ссылки" aria-label="Permalink to &quot;Ссылки&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const I=l(h,[["render",c]]);export{T as __pageData,I as default};
